DROP TABLE IF EXISTS `malicious_ips`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `malicious_ips` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '恶意IP记录ID',
  `ip_address` varchar(15) NOT NULL COMMENT 'IP地址',
  `first_seen` datetime NOT NULL COMMENT '首次发现时间',
  `last_seen` datetime NOT NULL COMMENT '最后活动时间',
  `attack_count` int(11) NOT NULL COMMENT '攻击次数',
  `attack_types` text COMMENT '攻击类型列表',
  `threat_level` varchar(20) NOT NULL COMMENT '威胁等级',
  `is_marked` tinyint(1) NOT NULL COMMENT '是否被标记为恶意',
  `is_blocked` tinyint(1) NOT NULL COMMENT '是否被封禁',
  `blocked_time` datetime DEFAULT NULL COMMENT '封禁时间',
  `block_reason` text COMMENT '封禁原因',
  `block_until` datetime DEFAULT NULL COMMENT '封禁期限',
  `source_honeypots` text COMMENT '来源蜜罐ID列表',
  `location` varchar(100) DEFAULT NULL COMMENT '地理位置',
  `isp` varchar(100) DEFAULT NULL COMMENT 'ISP信息',
  `notes` text COMMENT '备注',
  `created_at` datetime NOT NULL COMMENT '创建时间',
  `updated_at` datetime NOT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `ip_address` (`ip_address`)
) ENGINE=MyISAM AUTO_INCREMENT=49 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

