--
-- Table structure for table `match_rules`
--

DROP TABLE IF EXISTS `match_rules`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `match_rules` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '规则ID',
  `name` varchar(100) NOT NULL COMMENT '规则名称',
  `attack_type` varchar(50) NOT NULL COMMENT '攻击类型',
  `regex_pattern` text NOT NULL COMMENT '正则表达式',
  `threat_level` varchar(20) NOT NULL COMMENT '威胁等级',
  `description` text COMMENT '规则描述',
  `match_field` varchar(50) NOT NULL COMMENT '匹配字段',
  `is_enabled` tinyint(1) NOT NULL COMMENT '是否启用',
  `match_count` int(11) NOT NULL COMMENT '匹配次数统计',
  `last_matched` datetime DEFAULT NULL COMMENT '最后匹配时间',
  `priority` int(11) NOT NULL COMMENT '规则优先级',
  `auto_block` tinyint(1) NOT NULL COMMENT '是否自动封禁',
  `block_duration` int(11) NOT NULL COMMENT '封禁时长（小时）',
  `created_by` int(11) DEFAULT NULL COMMENT '创建者ID',
  `created_at` datetime NOT NULL COMMENT '创建时间',
  `updated_at` datetime NOT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `created_by` (`created_by`)
) ENGINE=MyISAM AUTO_INCREMENT=27 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

